function normalizeDomain(input: string): string {
  const value = input.trim().toLowerCase();
  if (!value) return YC_PROFILE.domain;
  return value.replace(/^https?:\/\//, '').replace(/\/.*$/, '');
}

function domainToDisplayName(domain: string): string {
  const withoutTld = domain.split('.')[0] || 'Frontier';
  return withoutTld
    .split(/[-_]/g)
    .filter(Boolean)
    .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ');
}

export function resolveInvestorProfile(domainInput: string): InvestorProfile {
  const domain = normalizeDomain(domainInput);
  if (domain === 'ycombinator.com' || domain.endsWith('.ycombinator.com')) {
    return YC_PROFILE;
  }

  return {
    ...FALLBACK_PROFILE,
    domain,
    name: `${domainToDisplayName(domain)} Ventures`,
  };
}

export function formatCompactUsd(value: number): string {
  const formatted = new Intl.NumberFormat('en-US', {
    notation: 'compact',
    maximumFractionDigits: 1,
  }).format(Math.abs(value));
  return `${value < 0 ? '-' : ''}$${formatted}`;
}
